const body = $input.first().json.body || {};
const numbers = Array.isArray(body.numbers) ? body.numbers : [4, 7, 9, 12];
// Inline the prompt (txt placeholder) and schema (json placeholder).
const systemPrompt = `{{HYDRATE:txt:common/prompts/demo_summary_prompt.txt}}`;
const schema = {{HYDRATE:json:common/prompts/demo_summary_schema.json}};
const payload = {
  model: 'openai/gpt-4o-mini',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: 'Numbers: ' + JSON.stringify(numbers) }
  ],
  temperature: 0,
  response_format: { type: 'json_schema', json_schema: { name: 'summary', strict: true, schema } }
};
return [{ json: { payload_built: true, numbers, schema_keys: Object.keys(schema.properties) } }];

const numbers = $input.first().json.numbers;
const sum = numbers.reduce((a, b) => a + b, 0);
const avg = numbers.length ? sum / numbers.length : 0;
let mood = 'balanced';
if (avg < 3) mood = 'low';
else if (avg > 8) mood = 'high';
// Mock response shape — same schema the LLM would emit. Demonstrates the
// structured-output contract (txt prompt + json schema placeholders) without
// hitting OpenRouter at runtime. Why mock instead of a real HTTP Request:
// the Code node above already inlines both placeholders, which is the
// pattern proof; making the actual HTTP call would require a per-tenant
// httpHeaderAuth credential that we cannot template (credentials.openRouter
// would need to be added to YAML, and templates would lose portability).
// To convert this to a real OpenRouter call: (1) create an httpHeaderAuth
// credential in n8n with `Authorization: Bearer $OPENROUTER_API_KEY`, (2)
// add `credentials: { openRouter: { id, name } }` to the env YAML, (3)
// replace this Code node with an HTTP Request node referencing that
// credential. See plan §4b 'demo_ai_summary' note + pattern-skills/llm-providers.md.
return [{ json: { ai: { count: numbers.length, sum, avg, mood } } }];
